.repository-page[data-v-dcb25a3e] {
  height: 100%;
  display: flex;
  flex-direction: column;
  background-color: var(--SmartThemeBlurTintColor);
}
.toolbar[data-v-dcb25a3e] {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 15px;
  border-bottom: 1px solid var(--SmartThemeBorderColor);
  background-color: var(--SmartThemeQuoteColor);
}
.search-container[data-v-dcb25a3e] {
  position: relative;
  flex: 1;
  max-width: 300px;
}
.search-input[data-v-dcb25a3e] {
  width: 100%;
  padding: 8px 12px;
  padding-right: 30px;
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 20px;
  background-color: var(--SmartThemeBlurTintColor);
  color: var(--SmartThemeBodyColor);
  font-size: 14px;
}
.search-input[data-v-dcb25a3e]:focus {
  outline: none;
  border-color: var(--SmartThemeBodyColor);
}
.clear-search[data-v-dcb25a3e] {
  position: absolute;
  right: 10px;
  top: 50%;
  transform: translateY(-50%);
  cursor: pointer;
  color: var(--SmartThemeBodyColor);
  opacity: 0.6;
}
.clear-search[data-v-dcb25a3e]:hover {
  opacity: 1;
}
.toolbar-actions[data-v-dcb25a3e] {
  display: flex;
  gap: 5px;
  margin-left: 15px;
}
.toolbar-button[data-v-dcb25a3e] {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 8px;
  background-color: var(--SmartThemeBlurTintColor);
  color: var(--SmartThemeBodyColor);
  cursor: pointer;
  transition: background-color 0.2s;
}
.toolbar-button[data-v-dcb25a3e]:hover {
  background-color: var(--SmartThemeQuoteColor);
}
.content-area[data-v-dcb25a3e] {
  flex: 1;
  overflow: hidden;
}
